{"code": "import sys

def main():
    n = int(sys.stdin.readline())
    dishes = []
    for _ in range(n):
        a, b = map(int, sys.stdin.readline().split())
        dishes.append((a, b))

    # Sort dishes by the sum of A_i + B_i in descending order
    dishes.sort(key=lambda x: x[0] + x[1], reverse=True)

    taka = 0
    aoki = 0
    for i in range(n):
        if i % 2 == 0:
            taka += dishes[i][0]
        else:
            aoki += dishes[i][1]

    print(taka - aoki)

